func NewIrisAdminServiceHTTPClient(client *http.Client) IrisAdminServiceHTTPClient {
	return &IrisAdminServiceHTTPClientImpl{client}
}

// ApplyKumoConfig ApplyKumoConfig renders the configuration, writes it to KumoMTA, and
// reloads the service. High-risk: requires confirmation and is audited.
func (c *IrisAdminServiceHTTPClientImpl) ApplyKumoConfig(ctx context.Context, in *ApplyKumoConfigRequest, opts ...http.CallOption) (*ApplyKumoConfigReply, error) {
	var out ApplyKumoConfigReply
	pattern := "/v1/kumomta/config:apply"
	path := binding.EncodeURL(pattern, in, false)
	opts = append(opts, http.Operation(OperationIrisAdminServiceApplyKumoConfig))
	opts = append(opts, http.PathTemplate(pattern))
	err := c.cc.Invoke(ctx, "POST", path, in, &out, opts...)
	if err != nil {
		return nil, err
	}
	return &out, nil
}

